 1	import * as React from 'react';
 2	import {
 3	  DescriptionList,
 4	  DescriptionListDescription,
 5	} from '@patternfly/react-core';
 6	import {
 7	  getGroupVersionKindForModel,
 8	  K8sKind,
 9	  ResourceLink,
10	} from '@openshift-console/dynamic-plugin-sdk';
11	import { RouteTemplate } from '../utils/triggers';
12	import { ExternalLinkWithCopy } from '../utils/link';
13	import './TriggerResourceLinks.scss';
14	
15	type TriggerResourceLinksProps = {
16	  namespace: string;
17	  model: K8sKind;
18	  links: RouteTemplate[];
19	};
20	const TriggerResourceLinks: React.FC<TriggerResourceLinksProps> = ({
21	  links = [],
22	  namespace,
23	  model,
24	}) => {
25	  if (links.length === 0) {
26	    return null;
27	  }
28	  return (
29	    <DescriptionList>
30	      {links.map(({ routeURL, triggerTemplateName }) => {
31	        return (
32	          <DescriptionListDescription key={triggerTemplateName}>
33	            <ResourceLink
34	              groupVersionKind={getGroupVersionKindForModel(model)}
35	              name={triggerTemplateName}
36	              namespace={namespace}
37	              title={triggerTemplateName}
38	              inline
39	            />
40	            {routeURL && (
41	              <div className="opp-trigger-template-link">
42	                <ExternalLinkWithCopy
43	                  key={routeURL}
44	                  link={routeURL}
45	                  text={routeURL}
46	                />
47	              </div>
48	            )}
49	          </DescriptionListDescription>
50	        );
51	      })}
52	    </DescriptionList>
53	  );
54	};
55	
56	export default TriggerResourceLinks;

